'use strict';

const test = require('node:test');
const assert = require('node:assert/strict');
const { FlightPool } = require('../src/flightPool');
const { ResourceClient } = require('../src/resourceClient');

test('direct pool subscribers remain isolated when several peers leave', async () => {
  let calls = 0;
  let release;
  let upstreamAborted = false;
  const pool = new FlightPool((key, signal) => new Promise((resolve, reject) => {
    calls += 1;
    release = resolve;
    signal.addEventListener('abort', () => { upstreamAborted = true; reject(new Error('upstream aborted')); }, { once: true });
  }));
  const firstController = new AbortController();
  const secondController = new AbortController();
  const first = pool.load('crowded', firstController.signal);
  const second = pool.load('crowded', secondController.signal);
  const third = pool.load('crowded');
  const firstCheck = assert.rejects(first);
  const secondCheck = assert.rejects(second);
  await Promise.resolve();
  firstController.abort(new Error('first left'));
  secondController.abort(new Error('second left'));
  release('survived');
  await firstCheck;
  await secondCheck;
  assert.equal(await third, 'survived');
  assert.equal(upstreamAborted, false);
  assert.equal(calls, 1);
});

test('direct client retries a transient rejection and retains only success', async () => {
  let calls = 0;
  const client = new ResourceClient(async () => {
    calls += 1;
    if (calls === 1) throw new Error('transient');
    return { generation: calls };
  });
  await assert.rejects(client.get('record'));
  assert.deepEqual(await client.get('record'), { generation: 2 });
  assert.deepEqual(await client.get('record'), { generation: 2 });
  assert.equal(calls, 2);
});

test('integrated sharing survives one cancellation and still caches success', async () => {
  let calls = 0;
  let release;
  const client = new ResourceClient((key, signal) => new Promise((resolve, reject) => {
    calls += 1;
    release = resolve;
    signal.addEventListener('abort', () => reject(signal.reason || new Error('aborted')), { once: true });
  }));
  const departed = new AbortController();
  const cancelled = client.get('integrated', departed.signal);
  const cancelledCheck = assert.rejects(cancelled);
  const active = client.get('integrated');
  await Promise.resolve();
  departed.abort(new Error('navigation'));
  release('ready');
  await cancelledCheck;
  assert.equal(await active, 'ready');
  assert.equal(await client.get('integrated'), 'ready');
  assert.equal(calls, 1);
});
